/* ——— Label ——— */
:where([data-df="label"]) {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.875rem;
  line-height: 1;
  font-weight: 500;
  user-select: none;
}

/* ——— Separator ——— */
:where([data-df="separator"]) {
  flex-shrink: 0;
  background-color: var(--border);
  border: none;
}

:where([data-df="separator"][data-orientation="horizontal"]) {
  height: 1px;
  width: 100%;
}

:where([data-df="separator"][data-orientation="vertical"]) {
  width: 1px;
  align-self: stretch;
}

/* ——— Switch ——— */
:where([data-df="switch"]) {
  position: relative;
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  border-radius: 9999px;
  border: 1px solid transparent;
  transition: background-color 150ms, box-shadow 150ms;
  outline: none;
  cursor: pointer;
}

:where([data-df="switch"][data-size="default"]) {
  height: 18.4px;
  width: 32px;
}

:where([data-df="switch"][data-size="sm"]) {
  height: 14px;
  width: 24px;
}

:where([data-df="switch"][data-state="checked"]),
:where([data-df="switch"][aria-checked="true"]) {
  background-color: var(--primary);
}

:where([data-df="switch"][data-state="unchecked"]),
:where([data-df="switch"][aria-checked="false"]) {
  background-color: var(--input);
}

:where([data-df="switch"]:focus-visible) {
  border-color: var(--ring);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--ring) 50%, transparent);
}

:where([data-df="switch"]:disabled) {
  cursor: not-allowed;
  opacity: 0.5;
}

:where([data-df="switch-thumb"]) {
  pointer-events: none;
  display: block;
  border-radius: 9999px;
  background-color: var(--background);
  transition: transform 150ms;
}

:where([data-df="switch"][data-suppress-thumb-transition] [data-df="switch-thumb"]) {
  transition: none;
}

:where([data-df="switch"][data-size="default"] [data-df="switch-thumb"]) {
  width: 1rem;
  height: 1rem;
}

:where([data-df="switch"][data-size="sm"] [data-df="switch-thumb"]) {
  width: 0.75rem;
  height: 0.75rem;
}

:where([data-df="switch"][aria-checked="true"] [data-df="switch-thumb"]),
:where([data-df="switch"][data-state="checked"] [data-df="switch-thumb"]) {
  transform: translateX(calc(100% - 2px));
}

:where([data-df="switch"][aria-checked="false"] [data-df="switch-thumb"]),
:where([data-df="switch"][data-state="unchecked"] [data-df="switch-thumb"]) {
  transform: translateX(0);
}

/* ——— Slider ——— */
:where([data-df="slider"]) {
  display: flex;
  width: 100%;
  touch-action: none;
  user-select: none;
  align-items: center;
}

:where([data-df="slider"][data-disabled]) {
