}

:where([data-df="slider-track"]) {
  position: relative;
  flex-grow: 1;
  overflow: hidden;
  border-radius: var(--radius-4xl);
  background-color: var(--muted);
  height: 0.75rem;
  width: 100%;
}

:where([data-df="slider-range"]) {
  position: absolute;
  background-color: var(--primary);
  height: 100%;
  border-radius: inherit;
}

:where([data-df="slider-thumb"]) {
  display: block;
  width: 1rem;
  height: 1rem;
  flex-shrink: 0;
  border-radius: var(--radius-4xl);
  border: 1px solid var(--primary);
  background-color: #fff;
  box-shadow: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  transition: box-shadow 150ms;
  outline: none;
  cursor: pointer;
}

:where([data-df="slider-thumb"]:hover),
:where([data-df="slider-thumb"]:focus-visible) {
  box-shadow: 0 0 0 4px color-mix(in oklch, var(--ring) 50%, transparent);
}

/* ——— Toggle / Toggle Group ——— */
:where([data-df="toggle"]),
:where([data-df="toggle-group-item"]) {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.25rem;
