}

:where([data-df="toggle"]:hover),
:where([data-df="toggle-group-item"]:hover) {
  background-color: var(--muted);
  color: var(--foreground);
}

:where([data-df="toggle"]:focus-visible),
:where([data-df="toggle-group-item"]:focus-visible) {
  border-color: var(--ring);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--ring) 50%, transparent);
  z-index: 10;
}

:where([data-df="toggle"][aria-pressed="true"]),
:where([data-df="toggle-group-item"][data-state="on"]),
:where([data-df="toggle-group-item"][aria-pressed="true"]) {
