  color: var(--foreground);
}

:where([data-df="toggle"][data-variant="outline"]),
:where([data-df="toggle-group-item"][data-variant="outline"]) {
  border-color: var(--input);
}

:where([data-df="toggle"][data-size="default"]),
:where([data-df="toggle-group-item"][data-size="default"]) {
  height: 2.25rem;
  min-width: 2.25rem;
  padding-inline: 0.75rem;
}

:where([data-df="toggle"][data-size="sm"]),
:where([data-df="toggle-group-item"][data-size="sm"]) {
  height: 2rem;
  min-width: 2rem;
  padding-inline: 0.75rem;
}

:where([data-df="toggle"][data-size="lg"]),
:where([data-df="toggle-group-item"][data-size="lg"]) {
  height: 2.5rem;
  min-width: 2.5rem;
  padding-inline: 1rem;
}

:where([data-df="toggle-group"]) {
  display: flex;
  width: fit-content;
  flex-direction: row;
  align-items: center;
  gap: calc(var(--gap, 2) * 0.25rem);
}

:where([data-df="toggle-group"][data-orientation="vertical"]) {
