  align-items: stretch;
}

:where([data-df="toggle-group"][data-spacing="0"][data-variant="outline"]) {
  border-radius: var(--df-toggle-radius, var(--radius-4xl));
}

:where([data-df="toggle-group"][data-spacing="0"] [data-df="toggle-group-item"]) {
  border-radius: 0;
  box-shadow: none;
}

:where([data-df="toggle-group"][data-spacing="0"][data-orientation="horizontal"]
