:where([data-df="toggle-group"][data-spacing="0"][data-orientation="horizontal"]
  [data-df="toggle-group-item"]:last-child) {
  border-top-right-radius: var(--df-toggle-radius, var(--radius-3xl));
  border-bottom-right-radius: var(--df-toggle-radius, var(--radius-3xl));
}

:where([data-df="toggle-group"][data-spacing="0"][data-variant="outline"][data-orientation="horizontal"]
  [data-df="toggle-group-item"]:not(:first-child)) {
  border-left-width: 0;
}

:where([data-df="toggle-group"][data-spacing="0"][data-orientation="vertical"]
  [data-df="toggle-group-item"]:first-child) {
  border-top-left-radius: var(--df-toggle-radius, var(--radius-3xl));
  border-top-right-radius: var(--df-toggle-radius, var(--radius-3xl));
}

:where([data-df="toggle-group"][data-spacing="0"][data-orientation="vertical"]
  [data-df="toggle-group-item"]:last-child) {
  border-bottom-left-radius: var(--df-toggle-radius, var(--radius-3xl));
  border-bottom-right-radius: var(--df-toggle-radius, var(--radius-3xl));
}

