  [data-df="toggle-group-item"]:not(:first-child)) {
  border-top-width: 0;
}

/* Class-based toggle chrome — reliable path (Button-style); :where rules above are fallbacks */
.df-toggle-group {
  display: flex;
  width: fit-content;
  flex-direction: row;
  align-items: center;
  gap: calc(var(--gap, 2) * 0.25rem);
}
.df-toggle-group[data-orientation="vertical"] {
  flex-direction: column;
  align-items: stretch;
}
.df-toggle-group[data-spacing="0"][data-variant="outline"] {
  border-radius: var(--df-toggle-radius, var(--radius-4xl));
}
.df-toggle-item {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.25rem;
  flex-shrink: 0;
  border-radius: var(--df-toggle-radius, var(--radius-4xl));
  font-size: 0.875rem;
  line-height: 1.25rem;
  font-weight: 500;
  white-space: nowrap;
  transition: color 150ms, background-color 150ms, border-color 150ms,
    box-shadow 150ms;
  outline: none;
  cursor: pointer;
  background: transparent;
  border: 1px solid transparent;
  color: inherit;
  user-select: none;
}
.df-toggle-item svg {
  pointer-events: none;
  flex-shrink: 0;
  width: 1rem;
  height: 1rem;
}
.df-toggle-item:hover:not(:disabled) {
  background-color: var(--muted);
